-- ================================================================
-- INDEXES for common query patterns
-- ================================================================
-- Student lookup by status (admin student monitoring)
CREATE INDEX idx_students_status ON students(status);

-- Appointment queries by date and advisor (booking, queue, dashboard)
CREATE INDEX idx_appointments_date ON appointments(appointment_date);
CREATE INDEX idx_appointments_advisor_date ON appointments(advisor_id, appointment_date);
CREATE INDEX idx_appointments_student ON appointments(student_id);
CREATE INDEX idx_appointments_status ON appointments(status);

-- Queue lookups (live queue status page)
CREATE INDEX idx_queue_advisor_date ON queue_tokens(advisor_id, queue_date);
CREATE INDEX idx_queue_status ON queue_tokens(status);

-- Availability lookups (booking page, advisor list)
CREATE INDEX idx_availability_advisor ON availability_slots(advisor_id, day_of_week);

-- Penalty history (admin monitoring)
CREATE INDEX idx_penalties_student ON penalties(student_id);

-- Message inbox queries
CREATE INDEX idx_messages_receiver ON messages(receiver_id, is_read);
